164. /// <summary>
165. /// Default ordinalizer providing English ordinal suffixes (1st, 2nd, 3rd, etc.).
166. /// </summary>
167. // Anti-pattern: not sealed — leaf class (base for locale ordinalizers below)
168. // Actually, this IS a base class — keep it unsealed. But its derived classes should be sealed.
169. public class DefaultOrdinalizer : IOrdinalizer
170. {
171.     /// <inheritdoc />
172.     public virtual string Convert(int number, string numberString)
173.     {
174.         var suffix = (number % 100) switch
175.         {
176.             11 or 12 or 13 => "th",
177.             _ => (number % 10) switch
178.             {
179.                 1 => "st",
180.                 2 => "nd",
181.                 3 => "rd",
182.                 _ => "th"
183.             }
184.         };
185. 
186.         return numberString + suffix;
187.     }
188. }
