210. /// <summary>
211. /// Romanian ordinalizer providing locale-specific ordinal formatting.
212. /// </summary>
213. public sealed class RomanianOrdinalizer : DefaultOrdinalizer
214. {
215.     /// <inheritdoc />
216.     public override string Convert(int number, string numberString)
217.     {
218.         // Complex Romanian ordinal logic
219.         if (number < 0)
220.         {
221.             return numberString;
222.         }
223. 
224.         return (number % 100) switch
